#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int64_t A,B; scanf("%lld %lld", &A, &B);
        while((A & 1LL) == 0) A >>= 1;
        while((B & 1LL) == 0) B >>= 1;
        if(A == B) printf("YES\n"); else printf("NO\n");
    }
    return 0;
}

